const phases=[{id:'design',num:'01',name:'Architecture & Design',current:{sub:'Technical design → Architecture Decision Records → API contracts',tools:[{name:'Confluence',cls:'confluence'},{name:'Figma',cls:'other'},{name:'GitHub',cls:'github'}],activities:['Architecture Decision Records written in Confluence','API contract design (OpenAPI / Swagger)','Database schema and data modeling','User experience wireframes in Figma','Technical debt assessment and exploration spikes'],pains:['Design docs rarely linked to Jira stories — context lost at handoff','Architecture Decision Records written post-hoc, if at all','No consistency check between design and implementation','Architecture knowledge siloed in one or two senior engineers']},ai:{mode:'collab',modeLabel:'Human + AI',sub:'AI drafts → Human decides → Auto-documented to Confluence',tools:[{name:'Confluence',cls:'confluence'},{name:'GitHub',cls:'github'},{name:'Devin Desktop',cls:'devin'},{name:'Jira',cls:'jira'}],agentDoes:['Generates draft Architecture Decision Record from Jira epic and acceptance criteria','Proposes API contracts (OpenAPI) based on ticket scope and existing codebase patterns','Scans repo for prior decisions — surfaces conflicts or precedents automatically','Auto-publishes finalized design doc to Confluence, linked to the Jira epic'],humanFocuses:['Validates trade-offs and makes the architectural call — the "why"','Reviews AI-generated API contracts for business correctness','Approves or revises Architecture Decision Records before publishing','Flags novel requirements that need deeper exploration spikes'],gains:['Architecture Decision Records always written','Zero documentation lag','Design → ticket linked automatically']},devin:[{name:'Knowledge Base — Arch Standards',type:'knowledge',typeLabel:'Knowledge',link:'https://docs.devin.ai/product-guides/knowledge',setup:['Settings → Knowledge → Add Knowledge','Add: architecture guidelines, tech stack standards, forbidden patterns','Trigger: "when working on architecture, API design, or new services"','Pin to "all repos" → applies to every Devin session org-wide'],example:'!arch-standards\n"APIs use REST + OpenAPI 3.0. No raw SQL — use the ORM.\nAll new services require an OpenAPI spec before implementation."'},{name:'Ask Devin + DeepWiki',type:'ask',typeLabel:'Ask Devin',link:'https://docs.devin.ai/work-with-devin/ask-devin',setup:['Index repos: Settings → Repositories → Index','Use Ask Devin before any design work to understand existing patterns','DeepWiki: replace github.com with deepwiki.com in any repo URL'],example:'"What is our current authentication pattern across services? Any inconsistencies before designing the new auth flow?"'},{name:'AGENTS.md — Repo Conventions',type:'config',typeLabel:'Config',link:'https://docs.devin.ai/onboard-devin/agents-md',setup:['Create AGENTS.md in repo root','Document: architecture conventions, module boundaries, naming patterns','Devin reads this at the start of every session in that repo'],example:'# Architecture Conventions\n- gRPC internally, REST externally\n- No direct DB access from API layer\n- OpenAPI spec committed before coding starts'},{name:'Playbook — Design Review',type:'playbook',typeLabel:'Playbook',link:'https://docs.devin.ai/product-guides/creating-playbooks',setup:['Settings → Library → Playbooks → Create','Macro: !design-review','Define: review proposed design against existing patterns, flag conflicts','Add !design-review label to any Jira design ticket to trigger'],example:'!design-review on Jira ticket → Devin reads design doc, scans codebase for conflicts, flags inconsistencies, posts findings as Jira comment'}]},{id:'dev',num:'02',name:'Development',current:{sub:'Feature coding → Local testing → Pull request creation',tools:[{name:'GitHub',cls:'github'},{name:'Devin Desktop',cls:'devin'},{name:'Jira',cls:'jira'}],activities:['Feature branch cut from Jira ticket — link is manual','Coding with Devin Desktop used only as autocomplete','Local unit test writing','Pull request creation with description','Jira ticket status updated manually'],pains:['Devin Desktop cloud features ignored: no pull request agents, no background tasks, no async runs','Developer context lives in the engineer\'s head, not in the ticket or repo','Jira ↔ GitHub link is manual and frequently forgotten','AI used only for prompting — not as an autonomous agent owning a task end-to-end']},ai:{mode:'agent',modeLabel:'Agent-driven',sub:'Ticket assigned → Agent implements → Pull request opened autonomously',tools:[{name:'GitHub',cls:'github'},{name:'Devin Desktop',cls:'devin'},{name:'Jira',cls:'jira'}],agentDoes:['Picks up Jira ticket, reads acceptance criteria and linked design docs, cuts branch automatically','Implements feature across multiple files using Cascade or Devin autonomous mode','Writes unit and integration tests as part of implementation, not as an afterthought','Opens pull request with full description, links to Jira, self-assigns reviewers','Runs background tasks asynchronously — agent works while engineers are in meetings or offline'],humanFocuses:['Writes clear acceptance criteria and definition of done — this is the agent\'s specification','Unblocks agent when it hits ambiguous requirements via Teams or pull request comment','Reviews completed pull request for business logic and edge cases','Handles genuinely novel architecture with no prior codebase pattern'],gains:['Pull request agents active','Async background tasks','Jira ↔ GitHub auto-synced','Multi-file context used']},devin:[{name:'Jira Integration — Auto-Implement',type:'integration',typeLabel:'Integration',link:'https://docs.devin.ai/integrations/jira',setup:['Settings → Integrations → Jira → Connect','Create Devin service account in Jira (comments appear as bot)','Trigger: assign ticket to Devin OR add label "devin"','Trigger: @mention Devin in a Jira comment with instructions'],example:'Add label "devin" to ticket PROJ-123\n→ Devin implements → opens PR → posts PR link to Jira\n→ updates ticket status automatically'},{name:'Scheduled Sessions — Daily Dev Pickup',type:'schedule',typeLabel:'Scheduled',link:'https://docs.devin.ai/product-guides/scheduled-sessions',setup:['Settings → Schedules → Create Schedule','Cron: 0 9 * * 1-5  (weekdays 9am)','Attach !implement playbook','Teams notification → #dev-runs'],example:'Prompt: "Check Jira for all \'Ready for Dev\' tickets in project CORE. Pick top 3 by priority and implement each, opening a separate PR per ticket."'},{name:'Devin Desktop → Cloud Handoff',type:'windsurf',typeLabel:'Desktop',link:'https://docs.devin.ai/desktop/devin',setup:['Plan task locally in Cascade','Click "Send to Devin" in the Agent Command Center','Devin spins up cloud VM, continues implementation','You keep coding locally — both work in parallel'],example:'Draft approach in Cascade → hand off to Devin cloud → Devin runs tests, fixes errors, opens PR while you start the next ticket'},{name:'Skills — Repo Procedures',type:'skill',typeLabel:'Skill',link:'https://docs.devin.ai/product-guides/skills',setup:['Create .agents/skills/implement/SKILL.md in your repo','Document: test commands, lint, branch naming, PR conventions','Devin auto-discovers and follows the skill on every session'],example:'# implement\n1. npm install && npm run lint\n2. npm test (all must pass)\n3. Branch: feature/PROJ-XXX-description\n4. PR title: [PROJ-XXX] Description'}]},{id:'review',num:'03',name:'Code Review',current:{sub:'Pull request review → Feedback → Merge',tools:[{name:'GitHub',cls:'github'},{name:'Jira',cls:'jira'}],activities:['Peer pull request review — typically 2 approvals required','Inline comments and change requests','Security and style checks via CI linting','Merge to main or release branch','Jira ticket moved to "In Review" manually'],pains:['Review is the biggest bottleneck — average 24–48 hour wait per pull request','No AI reviewer to catch obvious issues before humans see the pull request','Reviewers lack business context from the original Jira ticket','Continuous integration failures block merge; triage is entirely manual']},ai:{mode:'collab',modeLabel:'Human + AI',sub:'AI pre-review → Human focuses on logic → Merge',tools:[{name:'GitHub',cls:'github'},{name:'Devin Desktop',cls:'devin'},{name:'Jira',cls:'jira'}],agentDoes:['Runs automated pre-review on every pull request: style, security, test coverage, naming','Surfaces the Jira ticket and acceptance criteria inline on the pull request','Triages CI failures: identifies root cause, links to prior failures, suggests fixes','Flags breaking changes against existing API contracts and downstream dependencies','Auto-approves low-risk pull requests per team-defined policy'],humanFocuses:['Reviews business logic, edge cases, and product correctness — not formatting','Makes merge or hold decision on high-risk or complex pull requests','Handles ambiguous trade-offs the agent flags but cannot resolve','Defines policy for what the agent can auto-merge vs. needs human approval'],gains:['< 1hr review cycle','Ticket context inline on every pull request','CI failures auto-triaged']},devin:[{name:'Devin Review — Auto-Review All PRs',type:'review',typeLabel:'Devin Review',link:'https://docs.devin.ai/work-with-devin/devin-review',setup:['Settings → Review → Add repositories → toggle auto-review ON','Triggers: PR opened, new commits pushed, draft marked ready','Features: smart diff grouping, bug catcher, codebase-aware chat','Free for public repos — replace github.com with devinreview.com'],example:'Every PR: bugs with severity levels, copy/move detection, inline fix suggestions. Enable Auto-Fix → Devin responds to its own findings automatically.'},{name:'REVIEW.md — Custom Review Rules',type:'config',typeLabel:'Config',link:'https://docs.devin.ai/work-with-devin/devin-review',setup:['Create REVIEW.md in repo root (scoped rules per subdirectory)','Define: critical areas, security rules, anti-patterns, what to skip','Settings → Review → Review Rules: add custom glob patterns'],example:'# Review Guidelines\n## Critical\n- src/auth/ — security review required\n- DB migrations must be backward-compatible\n## Ignore\n- src/generated/ — auto-generated'},{name:'Automation — CI Failure Auto-Fix',type:'automation',typeLabel:'Automation',link:'https://docs.devin.ai/product-guides/automations',setup:['Automations → Templates → "CI failure fixer"','Trigger: GitHub check run, conclusion = failure','Set ACU limit per session to cap cost'],example:'CI fails on PR → Devin triggered → reads failure logs → identifies root cause → pushes fix → CI re-runs. No human needed.'},{name:'Scheduled — Morning PR Summary',type:'schedule',typeLabel:'Scheduled',link:'https://docs.devin.ai/product-guides/scheduled-sessions',setup:['Settings → Schedules → Create','Cron: 0 8 * * 1-5  (weekdays 8am)','Teams notification → #code-review'],example:'Prompt: "Review all open PRs in org/repo open > 24 hours. Post 2-sentence summary of key issues to #code-review per PR."'}]},{id:'test',num:'04',name:'Test & QA',current:{sub:'Automated CI → Manual QA regression → Sign-off',tools:[{name:'GitHub',cls:'github'},{name:'Jira',cls:'jira'},{name:'CI/CD',cls:'other'}],activities:['Unit and integration tests run in CI pipeline','Manual QA regression testing','User Acceptance Testing with product and stakeholders','Bug filing back into Jira (manual)','Test case management in ad-hoc spreadsheets'],pains:['Test coverage is inconsistent — no enforcement or visibility','Manual QA is slow and highly error-prone','AI could generate test cases from acceptance criteria — completely unused','Bugs found late in QA are 5–10× more expensive to fix than at development time']},ai:{mode:'agent',modeLabel:'Agent-driven',sub:'Acceptance criteria in → Tests generated → Failures triaged automatically',tools:[{name:'GitHub',cls:'github'},{name:'Devin Desktop',cls:'devin'},{name:'Jira',cls:'jira'}],agentDoes:['Generates unit, integration, and edge-case test suites from Jira acceptance criteria','Runs regression suite on every pull request with root-cause analysis on failures','Enforces coverage thresholds at the PR gate — flags drops before merge, files regressions found nightly','Files regression bugs in Jira with full reproduction steps and stack trace','Identifies which existing tests are affected by a change before merging'],humanFocuses:['Writes acceptance criteria clearly enough for the agent to derive tests from','Reviews AI-generated test cases for business-critical path coverage','Performs exploratory testing on genuinely novel user experience flows','Tunes coverage thresholds and test policies per service'],gains:['Tests generated from acceptance criteria','Coverage enforced automatically','Bugs auto-filed to Jira']},devin:[{name:'Playbook — Write Tests',type:'playbook',typeLabel:'Playbook',link:'https://docs.devin.ai/product-guides/creating-playbooks',setup:['Settings → Library → Playbooks → Create, Macro: !write-tests','Define: testing framework, coverage targets, test file conventions','Add !write-tests label to any Jira ticket to trigger'],example:'!write-tests on ticket → Devin reads acceptance criteria → generates unit + integration + edge-case tests → runs them → opens PR. Coverage lift: 1.5–2×.'},{name:'Automation — Nightly Smoke Tests',type:'automation',typeLabel:'Automation',link:'https://docs.devin.ai/product-guides/automations',setup:['Automations → Templates → "Nightly QA & smoke tests"','Cron: 0 2 * * *  (2am nightly)','Configure: repo, test commands, Jira project','Teams notification → #qa-alerts'],example:'Every 2am: Devin runs full end-to-end suite → files Jira tickets for regressions with reproduction steps → posts summary to #qa-alerts'},{name:'Skill — test-before-pr',type:'skill',typeLabel:'Skill',link:'https://docs.devin.ai/product-guides/skills',setup:['Create .agents/skills/test-before-pr/SKILL.md','Document: install, lint, test commands and failure policy','Devin auto-invokes before opening any pull request'],example:'# test-before-pr\n1. npm install\n2. npm run lint — fix all issues\n3. npm test — all must pass\n4. npm run build — must succeed\nDo NOT open PR if any step fails.'},{name:'Scheduled — Weekly Coverage Audit',type:'schedule',typeLabel:'Scheduled',link:'https://docs.devin.ai/product-guides/scheduled-sessions',setup:['Settings → Schedules → Create, Cron: 0 9 * * 1  (Monday 9am)','Repos: select all service repos','Teams notification → #engineering'],example:'Prompt: "Analyze coverage across all services. For any below 80%, open a PR for the 10 lowest-covered files. File a Jira ticket for any below 60%."'}]},{id:'deploy',num:'05',name:'Release & Deploy',current:{sub:'Release cut → Deploy → Smoke tests',tools:[{name:'GitHub',cls:'github'},{name:'CI/CD',cls:'other'},{name:'Jira',cls:'jira'},{name:'Confluence',cls:'confluence'}],activities:['Release branch cut and version tagging','Changelog and release notes written manually from pull requests','Staged rollout (canary or blue-green)','Smoke tests run post-deploy','Jira release version close-out (manual)'],pains:['Release notes written manually by aggregating pull request titles — slow and incomplete','No deployment risk assessment beyond tribal knowledge','Runbooks in Confluence routinely outdated','Rollback decisions made ad hoc with no data support']},ai:{mode:'collab',modeLabel:'Human + AI',sub:'AI generates notes → Risk scored → Human approves release',tools:[{name:'GitHub',cls:'github'},{name:'CI/CD',cls:'other'},{name:'Jira',cls:'jira'},{name:'Confluence',cls:'confluence'}],agentDoes:['Generates release notes from merged pull request descriptions and linked Jira tickets','Scores deployment risk based on changed surface area, coverage delta, and prior incident history','Updates Confluence runbooks automatically when deployment config or infrastructure changes','Monitors post-deploy metrics, flags anomalies: hold, rollback, or continue','Closes Jira release version and notifies stakeholders on successful deploy'],humanFocuses:['Reviews risk score and makes final go / no-go decision','Handles escalations when the agent flags post-deploy anomalies','Approves release notes before external publication','Defines rollback policy thresholds the agent monitors against'],gains:['Auto release notes','Deployment risk scoring','Runbooks always current','Jira auto-closed on release']},devin:[{name:'Automation — Weekly Changelog',type:'automation',typeLabel:'Automation',link:'https://docs.devin.ai/product-guides/automations',setup:['Automations → Templates → "Weekly changelog"','Cron: 0 9 * * 5  (Friday 9am)','Configure: repo, Teams channel (#releases)'],example:'Every Friday: Devin compiles merged PRs → groups Features/Fixes/Maintenance → posts to #releases → updates Confluence release page'},{name:'Automation — Post-Deploy Runbook Update',type:'automation',typeLabel:'Automation',link:'https://docs.devin.ai/product-guides/automations',setup:['Automations → New → Webhook trigger','Wire CI/CD to POST to the Devin webhook URL on deploy','Action: "Update Confluence runbook for this service based on changes in this deploy"'],example:'CI/CD deploys → POST to Devin webhook → Devin reads diff → updates Confluence runbooks → posts summary to #releases'},{name:'Playbook — Release Checklist',type:'playbook',typeLabel:'Playbook',link:'https://docs.devin.ai/product-guides/creating-playbooks',setup:['Settings → Library → Playbooks → Create, Macro: !release','Define: pre-release checks, smoke tests, notifications'],example:'!release → Devin: verifies CI green, checks open blockers, generates release notes, tags release in GitHub, posts to #releases, closes Jira version'},{name:'Auto-Triage — #incidents Monitor',type:'triage',typeLabel:'Auto-Triage',link:'https://docs.devin.ai/product-guides/auto-triage',setup:['Automations → Templates → "Triage bug reports on Teams"','Select #incidents channel','Devin monitors 24/7 after deploys, spawns sub-agents per report'],example:'Error in #incidents → Devin triages severity → spawns investigation → posts root cause + fix → files Jira P1/P2 → notifies on-call'}]}];

