const agents=[{id:'zeus',emoji:'⚡',name:'Zeus',role:'Code Review Agent',phase:'03 · Code Review',trigger:'Schedule + GitHub Automation',schedule:'0 8 * * 1-5',playbook:'!review',slack:'#code-review',status:'configure',what:'Reviews every open pull request before a human touches it. Catches bugs, style issues, and security problems. Surfaces the original Jira ticket inline so reviewers have full context. Triages CI failures and optionally pushes fixes. Posts a morning digest to Teams with what needs attention.',setupSteps:['Create Playbook: Settings → Library → Playbooks → Create\nName: "Review" · Macro: !review\nInstructions: review for bugs (severity), style, security, test coverage, and Jira acceptance criteria compliance','Enable Auto-Review: Settings → Review → Add all repos → toggle "Auto-review all PRs"\nGives Zeus a real-time trigger on every PR open, not just on schedule','Create Schedule: Settings → Schedules → Create\nName: "Zeus — Morning Review" · Cron: 0 8 * * 1-5 · Attach !review playbook\nPrompt: "Review all open PRs in [org] open > 4 hours. Flag blockers. Post summary to #code-review."','Add Automation: Automations → Templates → "CI failure fixer"\nTrigger: GitHub check run failure · Repo: all repos\nGives Zeus a reflex to fix broken builds the moment they fail','Create REVIEW.md in each repo root with coding standards, critical paths, and patterns to flag'],jobDesc:['Reviews all PRs open > 4 hours: bugs, style, security, coverage gaps','Surfaces Jira ticket + acceptance criteria inline on every PR diff','Detects CI failures, identifies root cause, suggests or pushes fix','Auto-approves low-risk PRs (docs, config, minor fixes) per policy','Posts morning digest to #code-review: PR list, blockers, who must act','Flags PRs open > 48 hours as stale — escalates to Teams thread'],playbookSample:'# !review\nFor each PR in the queue:\n1. Read the linked Jira ticket and acceptance criteria\n2. Review diff for bugs (classify: severe/non-severe)\n3. Flag security concerns in auth, DB, and API surface\n4. Check test coverage delta — flag if it drops\n5. Post findings as GitHub review comments\n6. Summarize all PRs in a Teams message to #code-review'},{id:'hermes',emoji:'🪽',name:'Hermes',role:'Development Agent',phase:'02 · Development',trigger:'Schedule + Jira Automation',schedule:'0 9 * * 1-5',playbook:'!implement',slack:'#dev-runs',status:'configure',what:'Picks up Jira tickets from the "Ready for Dev" queue every morning and implements them autonomously. Cuts branches, writes code across multiple files, adds tests, and opens pull requests with full descriptions. Works overnight on larger tasks. Posts status updates to Teams.',setupSteps:['Create Playbook: Settings → Library → Playbooks → Create\nName: "Implement" · Macro: !implement\nInstructions: read acceptance criteria, implement end-to-end, write tests, open PR per SKILL.md conventions','Connect Jira: Settings → Integrations → Jira → Connect\nCreate Devin service account in Jira. Set default playbook to !implement\nEngineers assign tickets directly to Hermes from Jira','Create Schedule: Settings → Schedules → Create\nName: "Hermes — Daily Pickup" · Cron: 0 9 * * 1-5 · Attach !implement playbook\nPrompt: "Check Jira for all \'Ready for Dev\' tickets in project [PROJ]. Pick top 3 by priority. One PR per ticket."','Add SKILL.md to each repo: .agents/skills/implement/SKILL.md\nDocument: test commands, lint, branch naming, PR conventions','Add Knowledge: trigger "when implementing a Jira ticket"\nContent: coding standards, architecture patterns, things Hermes should never do'],jobDesc:['Pulls top-priority "Ready for Dev" Jira tickets every morning at 9am','Reads acceptance criteria, linked design docs, and Architecture Decision Records','Implements across multiple files using Devin cloud VM — works async overnight','Writes unit and integration tests as part of implementation','Opens pull request per ticket, auto-links to Jira, moves ticket to "In Review"','Posts PR links to #dev-runs — engineers arrive to PRs ready for review'],playbookSample:'# !implement\n1. Read Jira ticket, acceptance criteria, and linked design docs\n2. Check AGENTS.md and SKILL.md for repo conventions\n3. Cut branch: feature/[TICKET-ID]-short-description\n4. Implement the feature end-to-end\n5. Run @skills:test-before-pr — do not continue if it fails\n6. Open PR: title [TICKET-ID] Description, link to Jira\n7. Post PR link to Teams #dev-runs'},{id:'argus',emoji:'👁',name:'Argus',role:'QA & Test Agent',phase:'04 · Test & QA',trigger:'Nightly Schedule + CI Trigger',schedule:'0 2 * * *',playbook:'!test',slack:'#qa-alerts',status:'configure',what:'Runs the full regression suite every night. Files Jira tickets for every failure with complete reproduction steps and stack traces. Generates new test cases from acceptance criteria when coverage drops. Posts a nightly pass/fail report to Teams. Acts as the CI watchdog during the day.',setupSteps:['Create Playbook: Settings → Library → Playbooks → Create\nName: "Test" · Macro: !test\nInstructions: run full test suite, analyze failures, file Jira tickets, post summary to Teams','Create Schedule: Settings → Schedules → Create\nName: "Argus — Nightly QA" · Cron: 0 2 * * * · Attach !test playbook\nPrompt: "Run the full regression suite. File a Jira ticket for each failure with steps to reproduce and stack trace. Post pass/fail summary to #qa-alerts."','Add Automation: Automations → New\nTrigger: GitHub check run failure on main branch\nAction: "Investigate this CI failure. Flaky test or real regression? If real, file a Jira P1 bug."','Create SKILL.md: .agents/skills/test-before-pr/SKILL.md\nDocument: install, lint, test, build commands. Argus auto-invokes before any PR open.','Add Playbook !write-tests: attach to Jira tickets needing coverage increases'],jobDesc:['Runs full regression suite every night at 2am across all repos','Files Jira bugs for every failure: title, reproduction steps, full stack trace','Distinguishes flaky tests from real regressions — only files tickets for real failures','Generates test cases from acceptance criteria when coverage drops below threshold','Acts as CI watchdog during the day — investigates main branch failures in real time','Posts nightly summary to #qa-alerts: pass rate, new failures, flaky test count'],playbookSample:'# !test\n1. Run full test suite: npm test -- --coverage\n2. For each failure:\n   - Flaky test or real regression?\n   - If real: file Jira bug with title, steps to reproduce, stack trace\n3. If coverage < 80% (90% for auth/payments) in any module, flag it; P2 ticket if < 60%\n4. Post summary to #qa-alerts:\n   ✅ X passed · ❌ Y failed · ⚠️ Z flaky\n   Links to any new Jira tickets filed'},{id:'atlas',emoji:'🌍',name:'Atlas',role:'Release Agent',phase:'05 · Release & Deploy',trigger:'Weekly Schedule + CI/CD Webhook',schedule:'0 9 * * 5',playbook:'!release',slack:'#releases',status:'configure',what:'Handles the entire release process every Friday. Compiles a categorized changelog from merged PRs and Jira tickets, tags the release in GitHub, updates Confluence release pages and runbooks, closes the Jira release version, and notifies stakeholders. Post-deploy, monitors #incidents for issues.',setupSteps:['Create Playbook: Settings → Library → Playbooks → Create\nName: "Release" · Macro: !release\nInstructions: compile changelog, verify CI green, tag release, update Confluence, close Jira version, notify stakeholders','Create Schedule: Settings → Schedules → Create\nName: "Atlas — Weekly Release" · Cron: 0 9 * * 5 (Friday 9am) · Attach !release playbook\nPrompt: "Compile all merged PRs from this week. Tag release in GitHub. Update Confluence release page. Post to #releases."','Add Webhook Automation: Automations → New → Webhook trigger\nCopy the webhook URL. Wire your CI/CD pipeline to POST to it on every production deploy\nAction: "Update Confluence runbooks for all services changed in this deploy"','Enable Auto-Triage: Automations → Templates → "Triage bug reports on Teams"\nSelect #incidents channel. Atlas monitors for post-deploy issues 24/7','Create Knowledge: "After each deploy, notify #releases with a 3-sentence summary of what changed"'],jobDesc:['Every Friday: compiles changelog from all merged PRs and linked Jira tickets','Categorizes changes: Features, Bug Fixes, Performance, Maintenance','Tags release in GitHub, updates Confluence release page and runbooks','Closes the Jira release version, moves open tickets to next sprint','Monitors #incidents 24/7 post-deploy — triages reports with sub-agents','Posts release summary to #releases — zero manual writing required'],playbookSample:'# !release\n1. Verify CI is green on main branch\n2. Check for open P1/P2 Jira blockers — halt if any\n3. Compile changelog: all merged PRs since last release\n   ✨ Features | 🐛 Fixes | ⚡ Performance | 🔧 Maintenance\n4. Tag release in GitHub: vYYYY.MM.DD\n5. Update Confluence release page with changelog\n6. Close Jira release version\n7. Post to #releases with changelog and release tag link'},{id:'hephaestus',emoji:'🔧',name:'Hephaestus',role:'Maintenance Agent',phase:'Cross-cutting',trigger:'Weekly Schedule',schedule:'0 7 * * 1',playbook:'!maintenance',slack:'#engineering',status:'configure',what:'Runs every Monday morning before the team starts work. Scans for outdated dependencies, opens update PRs. Removes dead code and unused feature flags. Runs security audits. Ensures the codebase is clean and ready for the week ahead. Reports findings to #engineering.',setupSteps:['Create Playbook: Settings → Library → Playbooks → Create\nName: "Maintenance" · Macro: !maintenance\nInstructions: dependency updates, dead code removal, security audit, linting fixes','Create Schedule: Settings → Schedules → Create\nName: "Hephaestus — Monday Maintenance" · Cron: 0 7 * * 1 (Monday 7am)\nPrompt: "Scan all repos for: (1) outdated dependencies — open update PRs, (2) unused feature flags, (3) security audit — file Jira tickets. Post summary to #engineering."','Add Automation: Automations → Templates → "Weekly dependency updates"\nReady-made template — configure with your repos and Teams channel','Add Knowledge: "Never auto-merge dependency updates for packages affecting auth, payments, or database connections — require human review"','Optional: add Snyk/Dependabot webhook to trigger Hephaestus immediately on critical CVEs'],jobDesc:['Scans all repos for outdated dependencies every Monday at 7am','Opens dependency update PRs grouped by risk level (patch / minor / major)','Identifies and removes dead code, unused imports, and retired feature flags','Runs security audit — files Jira tickets for CVEs or vulnerable packages','Fixes lint warnings and auto-formatting issues across the codebase','Posts weekly health report to #engineering before standup'],playbookSample:'# !maintenance\n1. Scan for outdated packages: npm outdated\n   - Patch updates: open PR immediately\n   - Minor/major: open PR + flag for human review\n2. Find dead code: unused exports, unreferenced files\n   Open PR to remove — one PR per module\n3. Security audit: npm audit\n   File Jira ticket for each HIGH or CRITICAL CVE\n4. Run linter with --fix, open PR\n5. Post summary to #engineering'},{id:'themis',emoji:'⚖️',name:'Themis',role:'Security & Compliance Agent',phase:'Cross-cutting',trigger:'PR Automation + Weekly Schedule',schedule:'0 10 * * 3',playbook:'!security-review',slack:'#security',status:'configure',what:'Watches every PR that touches sensitive paths (auth, payments, data access) and runs a deep security review before humans approve. Runs a weekly compliance sweep. Responds to CI security tool findings automatically. Files Jira security tickets with severity ratings.',setupSteps:['Create Playbook: Settings → Library → Playbooks → Create\nName: "Security Review" · Macro: !security-review\nInstructions: OWASP Top 10, injection, secret detection, auth bypass, insecure deserialization','Create REVIEW.md in security-sensitive repos:\n# Security Review Required\n- src/auth/ — auth bypass, token handling\n- src/payments/ — injection, PCI compliance','Add Automation: Automations → New\nTrigger: GitHub PR opened, path contains "auth/" OR "payments/" OR "database/"\nAction: trigger Themis security review session','Add Automation: Automations → New → Webhook trigger\nWire Snyk/SonarQube to POST findings to Devin webhook\nAction: "Investigate this security finding and open a fix PR if possible"','Create Schedule: Cron: 0 10 * * 3 (Wednesday 10am)\nPrompt: "Run security sweep: hardcoded secrets, overly permissive roles, unvalidated inputs, outdated CVEs."'],jobDesc:['Reviews every PR touching auth, payments, or data access before it merges','Checks for: injection vulnerabilities, hardcoded secrets, insecure token handling','Responds to SAST tool findings (Snyk, SonarQube) — investigates and opens fix PRs','Weekly codebase sweep: secret detection, permission review, CVE scan','Files Jira security tickets with CVSS severity, affected files, and remediation steps','Posts weekly security posture summary to #security — trend over time'],playbookSample:'# !security-review\nFor any PR touching src/auth/, src/payments/, src/data/:\n1. Check for injection vulnerabilities (SQL, command, LDAP)\n2. Review token/secret handling — no hardcoded values\n3. Verify input validation on all public endpoints\n4. Check for insecure direct object references\n5. Review error messages — no stack traces in responses\n6. Post findings as GitHub review comments with severity\n7. File Jira security ticket for MEDIUM or above'}];

